#include <bits/stdc++.h>
using namespace std;

const int mod=998244353,inv2=(mod+1)/2;

int n,m,e[20],f[1<<18],b[1<<18],ones[1<<18];

int main(){
    scanf("%d%d",&n,&m);
    for(int i=0,u,v;i<m;i++){
        scanf("%d%d",&u,&v);
        e[u]|=(1<<v-1);
        e[v]|=(1<<u-1);
    }
    for(int i=1;i<1<<n;i++){
        ones[i]=ones[i-(i&(-i))]+1;
        b[i]=1;
        for(int j=1;j<=n && b[i];j++)
            if((e[j]&i) && ((i>>j-1)&1))
                b[i]=0;
    }
    f[0]=1;
    for(int i=1;i<1<<n;i++){
        for(int j=i;j;j=(j-1)&i)
            if(b[j]){
                if(ones[j]%2)
                    f[i]=(f[i]+f[i-j])%mod;
                else
                    f[i]=(f[i]+mod-f[i-j])%mod;
            }
    }
    printf("%d",1ll*f[(1<<n)-1]*m%mod*inv2%mod);
    return 0;
}
